import { useState } from "react";
import api from "../../api/axios";
import { useNavigate } from "react-router-dom";
import { addLead } from "../../api/leadApi";
v

export default function AddLead() {
  const navigate = useNavigate();
  const [form, setForm] = useState({
    name: "",
    contact_number: "",
    email: "",
    lead_source: "",
    interest_level: "medium",
  });

  const handleChange = e =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async e => {
    e.preventDefault();
    await api.post("/leads/add", form);
    navigate("/leads");
  };

  return (
    <div style={{ maxWidth: 400, margin: "20px auto" }}>
      <h2>Add Lead</h2>

      <form onSubmit={submit}>
        <input name="name" placeholder="Name" onChange={handleChange} required />
        <input name="contact_number" placeholder="Contact Number" onChange={handleChange} required />
        <input name="email" placeholder="Email" onChange={handleChange} required />
        <input name="lead_source" placeholder="Lead Source" onChange={handleChange} required />

        <select name="interest_level" onChange={handleChange}>
          <option value="low">Low</option>
          <option value="medium">Medium</option>
          <option value="high">High</option>
        </select>

        <button type="submit">Save Lead</button>
      </form>
    </div>
  );
}
